CREATE TABLE `medicinal_plants` (
  `id` int(11) NOT NULL,
  `plant_name` varchar(100) NOT NULL,
  `sanskrit_name` varchar(100) DEFAULT NULL,
  `scientific_name` varchar(150) DEFAULT NULL,
  `other_names` varchar(200) DEFAULT NULL,
  `benefits` text DEFAULT NULL,
  `image` varchar(255) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `medicinal_plants`
--

INSERT INTO `medicinal_plants` (`id`, `plant_name`, `sanskrit_name`, `scientific_name`, `other_names`, `benefits`, `image`) VALUES
(1, 'Snakeroot', 'Śālapaṣpā', 'Rauvolfia serpentina', 'Devil pepper, Serpentine wood, Sarpagandha, Chandrika, and snakewood', 'Widely used for balancing Vāta disorders such as:\r\nFemale reproductive disorders,\r\nGeneral body weakness and fatigue,\r\nVāta-related diseases like joint pain.\r\nIt balances Vāta and Pitta, used for \r\nStrengthening (Balya), and also\r\nAnti-inflammatory.\r\nIt is important because it is a key ingredient in many classical Ayurvedic formulations for rejuvenation and strength.', 'Rauvolfia_serpentina.jpg\r\n'),
(2, 'Sweet Flag', 'Vacā', 'Acorus calamus', NULL, 'It is a powerful herb used in neurological and digestive disorders. It is used to \r\nImproves speech and memory,Mental disorders (Unmāda), Digestive stimulant.\r\nIt also enhances brain function,Removes toxins (Āma), Stimulates digestion.\r\nIt is widely used in children for speech development and cognitive improvement.', 'Acorus_calamus.jpg'),
(3, 'Common juniper', 'Hapuṣā', 'Juniperus communis', 'Juniperberry,Juniper', 'Hapuṣā is an aromatic plant known for its strong digestive and urinary benefits.It is used for Urinary disorders, Digestive problems, Gas and bloating.It is also\r\nDiuretic (increases urine flow), Carminative, Detoxifying. It\r\nhelps cleanse the urinary system and improves metabolism.', 'Juniperus_communis_fruits.jpg'),
(4, 'False black pepper', 'Kṛmihā / Viḍaṅga ', 'Embelia ribes', 'White-flowered Embelia, Vidanga, Vavding, Nainidang', 'It is used for removing intestinal worms,\r\ncuring skin diseases, digestive cleansing,\r\nStrong anthelmintic (kills worms),\r\nDetoxifying, Improves digestion\r\nIt is very effective in children and adults for parasite infections.', 'Embelia_ribes.jpg'),
(5, 'Indrayava', 'Kutaja tree', 'Holarrhena pubescens ', 'Kalinga, Vatsaka, Indrabīja, Holarrhena antidysenterica (Latin name)', ' It is highly effective for chronic digestive disorders. It is also used for \r\nChronic diarrhea ,Fever with loose motions, Digestive issues.It has Cooling, Anti-diarrheal, Strengthens intestines properties. it is also used when diarrhea becomes long-term or severe.', 'Holarrhena_pubescens.jpg'),
(6, 'Hingu', 'Hingu', 'Ferula asafoetida', 'The other names for hingu include:\r\nFerula narthex, Asafoetida, Devil\'s dung, Food of the God, Hing.', 'Hiṅgu (asafoetida) is a powerful spice and medicine widely used in Indian households.\r\nIt is also used for Severe gas, Abdominal pain, Colic disorders. It has properties like Strong carminative, Vāta-Kapha pacifier, Antispasmodic. It is one of the best remedies for digestive disorders and gas problems.', 'Ferula_assa-foetida.jpg'),
(7, 'Elaichi', 'Suksmaila', 'Elettaria cardamomum', 'Ela,Elaichi,cardamomum', 'Elaichi (cardamom) offers significant health benefits, including enhanced digestion, reduced blood pressure, and improved oral health. Rich in antioxidants and diuretic properties, it aids in reducing inflammation, fighting bad breath, and aiding respiratory health.', 'Elaichi.jpeg'),
(0, 'Kesara', 'Kesara', 'Crocus sativus', 'saffron crocus,Saffron,Kesar', 'Saffron helps in improving mood and reducing depression symptoms, supporting weight loss by reducing appetite, enhancing memory, treating PMS symptoms, and potentially protecting against age-related eye diseases.', 'Saffron.jpeg'),
(8, 'Kesara', 'Kesara', 'Crocus sativus', 'saffron crocus,Saffron,Kesar', 'Saffron helps in improving mood and reducing depression symptoms, supporting weight loss by reducing appetite, enhancing memory, treating PMS symptoms, and potentially protecting against age-related eye diseases.', 'Saffron.jpeg'),
(9, 'Tvak', 'Tvak', 'Cinnamomum zeylanicum', 'Dalchini ,cassia, canella ', 'Cinnamon helps combat oxidative stress and chronic inflammation, which reduces the risk of heart disease by lowering bad cholesterol (LDL) and triglycerides. Beyond metabolic support, cinnamon possesses antibacterial and antiviral properties that aid digestion, boost immunity, and may even support brain health by protecting against neurodegenerative conditions.', 'Cinnamon.jpeg'),
(10, 'Patra', 'Tamalapatra', 'Cinnamomum tamala', 'Malabar leaf, Indian cassia, Tejpatta.', 'Tamalapatra helps in aiding digestion, reducing inflammation, and managing blood sugar levels.', 'tamalapatra.jpeg'),
(11, 'Tuga', 'Tuga', 'Hibiscus abelmoschus', 'ambrette seed, musk mallow, musk okra, or muskdana', 'Musk seed promote heart health, boost immunity, improve digestion, strengthen bones, and support skin and hair health due to high antioxidant content', 'Musk seed.jpeg'),
(12, 'Dhanyaka', 'Dhanyaka', 'Coriandrum sativum', 'Coriander, Dhania', 'corainder helps to lower blood sugar, improved digestion, reduced inflammation, and enhanced heart health.', 'Coriander.jpeg'),
(13, 'Jiraka', 'Cuminum cyminum', 'Jiraka', 'cumin, jeera', 'cumin helps in promoting digestion, boosting immunity, and aiding weight management.', 'Jeera.jpeg'),
(14, 'Pippali', 'Pippali', 'Piper longum', 'Pipli, long pepper, Tippili', 'Pippali helps in improving digestion, supporting respiratory health, and increasing nutrient bio availability.', 'long pepper.jpeg'),
(15, 'Cavya', 'Cavya', 'Piper chaba', 'Chavya, Piper retrofractum Vahl, Piper chaba Hunter.', 'chavya helps in improves digestive health, metabolism, and immunity.', 'chavya.jpeg'),
(16, 'Citraka', 'Citraka', 'Plumbago zeylanica', 'Leadwort, Ceylon Leadwort, White Leadwort, Doctorbush.', 'Citraka helps to improve digestion, boost metabolism for weight loss, and manage chronic conditions like piles, arthritis, and skin disorders.', 'citraka.jpeg'),
(17, 'Nagara', 'Nagara', 'Zingiber officinale', 'Dry Ginger, Viśvabheṣaj, Viśva, Śṛṅgavera, Mahaushadha, Vishvaushadha, Rahuchatra, Katubhed, Katukandh', 'Nagara acts as a potent digestive aid, anti-inflammatory, and remedy for respiratory issues like coughs, cold, and bronchitis.', 'nagara.jpeg'),
(18, 'Marica', 'Marica', 'Piper nigrum', 'Kalimirch, Kali Mirchi, Golmirch, Gulmirch, Milagu, Nallumulku, Milaku, Kari, Miriyalu, Marichamu, Miriyalatige.', 'Marica helps in boosts nutrient absorption, aids digestion, and reduces inflammation.', 'Marica.jpeg'),
(19, 'Dipyaka', 'Dipyaka', 'Trachyspermum ammi', 'Ajwain seeds, Bishop\'s weed, Ajowan caraway, Celery seed, Yavānī, Ajamoda, Kharashva, Deepyaka, Bhrmakusha, Kharvi, and Ugragandhika.', 'Dipyaka aids in digestion, eases respiratory issues, and provides pain relief. It acts as a powerful antimicrobial agent, reduces bloating, relieves indigestion and acidity, eases joint pain, helps manage weight by boosting metabolism, and assists in managing respiratory conditions like asthma.', 'Ajwain.jpeg'),
(20, 'Amlavetasa', 'Amlavetasa', 'Garcinia cambogia', 'Malabar tamarind, Garcinia gummi-gutta, brindleberry, fish tamarind.', 'Malabar tamarind helps in supporting weight loss by suppressing appetite and blocking fat production and also acts as a digestive agent and sour agent.', 'malabar tamarind.jpeg'),
(21, 'Sandalwood', 'Candana', 'Santalum album', 'Chandan, Safed Chandan, Gandha, Sandanam, Chandanam, Srigandha, White Sandalwood, Sandal', 'Strong cooling effect (reduces body heat). Relieves burning sensation and fever. Improves skin (acne, pigmentation, rashes). Calms mind and reduces stress. Antiseptic and anti-inflammatory', 'chandana.jpeg'),
(22, 'Vetiver', 'Usīra', 'Vetiveria zizanioides', 'Khus, Khus-khus, Vettiveru, Vettiver, Ramacham, Lavancha, Vetiver root', 'Powerful body coolant. Relieves burning sensation and thirst. Useful in urinary disorders. Blood purifier. Reduces sweating and body odor', 'Vetiver.jpeg'),
(23, 'Indian Cedar', 'Tuni', 'Cedrela toona', 'Toon, Tun, Red cedar, Toona tree, Suren', 'Astringent (tightens tissues). Helps digestion. Anti-inflammatory. Useful in diarrhea and dysentery. Promotes wound healing', 'Cedrela toona.jpeg'),
(24, 'Agarwood', 'Aguru', 'Aquilaria agallocha', 'Oud, Agar, Eaglewood, Aloeswood', 'Calms mind and relieves stress. Improves digestion. Pain-relieving properties. Used in perfumes and rituals. Helps in respiratory disorders', 'agarwood.jpeg'),
(25, 'Turmeric', 'Haridrā', 'Curcuma longa', 'Haldi, Pasupu, Manjal, Arishina, Manjal, Indian saffron, Yellow root', 'Powerful anti-inflammatory. Blood purifier. Boosts immunity. Improves digestion. Heals wounds and skin diseases. Antioxidant and antimicrobial', 'turmeric.jpeg'),
(26, 'Camphor', 'Karpūra', 'Cinnamomum camphora', 'Kapoor, Karpooram, Karpura, Camphor crystal, Bhimseni kapoor', 'Relieves cough and cold. Acts as antiseptic and antimicrobial. Reduces itching and skin infections. Relieves headache. Improves blood circulation (external use)', 'camphor.jpeg'),
(27, 'Mace', 'Jātīpatrī', 'Myristica fragrans', 'Javitri, Japatri, Jathipathri, Mace spice, Nutmeg aril', 'Helps in diarrhea. Improves digestion. Relieves mouth disorders. Pain-relieving. Enhances appetite', 'mace.jpeg'),
(28, 'Nutmeg', 'Jātīphala', 'Myristica fragrans', 'Jaiphal, Jajikaya, Jathikkai, Jaajikaayi, Nutmeg seed', 'Promotes sleep (useful in insomnia). Improves digestion. Treats diarrhea. Strengthens nervous system. Reduces anxiety and stress', 'nutmeg.jpeg'),
(29, 'Chaste Tree', 'Harenu', 'Vitex agnus-castus', 'Chaste berry, Monk’s pepper, Nirgundi (related plant), Five-leaved chaste tree', 'Helps in digestion. Reduces inflammation. Useful in fever. Hormonal balance support. Supports reproductive health', 'Harenu.jpeg'),
(30, 'Indian Valerian', 'Tagara', 'Valeriana wallichii', 'Sugandh Bala, Tagaramu, Indian valerian root, Mushkbala', 'Treats insomnia. Reduces anxiety and stress. Calms nervous system. Pain-relieving. Useful in neurological disorders', 'Tagara.jpeg');

